# Well-designed clarification tool schema
CLARIFY_TOOL = {
    "name": "ask_human",
    "description": (
        "Ask the human user for information or a decision that you cannot determine from context. "
        "Use ONLY when: (1) the user's intent is genuinely ambiguous, "
        "(2) a subjective decision requires the user's preference, or "
        "(3) you lack a specific piece of information that only the user holds. "
        "Do NOT ask to confirm obvious steps or repeat information already provided."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "context": {
                "type": "string",
                "description": "What you are doing when this question arises — helps the user understand why.",
            },
            "question": {
                "type": "string",
                "description": "The specific question. Must be answerable in one sentence or a selection.",
            },
            "options": {
                "type": "array",
                "items": {"type": "string"},
                "description": "If the answer is one of a known set of choices, list them here.",
            },
            "default": {
                "type": "string",
                "description": "The value to use if the user does not respond within the timeout.",
            },
        },
        "required": ["context", "question"],
    },
}

# Example of a GOOD clarification call:
good_question = {
    "context": "Drafting a reply to Jennifer's meeting request for next Tuesday.",
    "question": "Should I accept on your behalf or ask for an alternative time?",
    "options": ["Accept", "Decline and suggest Wednesday", "Ask Jennifer for options"],
}

# Example of a BAD clarification call (too vague, missing context):
bad_question = {
    "context": "Processing your calendar",
    "question": "What do you want to do?",
    # No options, no context — the user cannot answer this meaningfully
}

# Batch clarification: collect all unknowns in a planning pass, ask once
import anthropic, json

client = anthropic.Anthropic()

PLAN_TOOL = {
    "name": "identify_unknowns",
    "description": (
        "Before starting execution, identify ALL ambiguities or missing inputs that you will "
        "need to complete this task. Return them as a list so they can be asked in a single batch."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "unknowns": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "id":       {"type": "string", "description": "Short identifier, e.g. 'reply_tone'"},
                        "question": {"type": "string"},
                        "options":  {"type": "array", "items": {"type": "string"}},
                        "default":  {"type": "string"},
                    },
                    "required": ["id", "question"],
                },
            },
        },
        "required": ["unknowns"],
    },
}

def plan_and_clarify(task: str, ask_human_batch: callable) -> dict[str, str]:
    """
    Phase 1: ask the model to identify ALL unknowns.
    Phase 2: ask the human for all of them in one pass.
    Returns a dict of {unknown_id: answer}.
    """
    response = client.messages.create(
        model="claude-opus-4-8",
        max_tokens=1024,
        tools=[PLAN_TOOL],
        messages=[{
            "role": "user",
            "content": (
                f"Task: {task}\n\n"
                "Before starting, identify ALL ambiguities or missing inputs you will need. "
                "Do not start executing yet."
            ),
        }],
        tool_choice={"type": "tool", "name": "identify_unknowns"},
    )

    unknowns = []
    for block in response.content:
        if block.type == "tool_use" and block.name == "identify_unknowns":
            unknowns = block.input["unknowns"]
            break

    if not unknowns:
        return {}   # no clarification needed

    # Ask all at once — one round-trip
    return ask_human_batch(unknowns)

# Example: CLI batch ask
def cli_batch_ask(unknowns: list[dict]) -> dict[str, str]:
    answers = {}
    print("\nThe agent needs a few inputs before starting:\n")
    for u in unknowns:
        print(f"Q: {u['question']}")
        if u.get('options'):
            for i, opt in enumerate(u['options'], 1):
                print(f"   {i}. {opt}")
            choice = input("   Answer: ").strip()
            if choice.isdigit() and 1 <= int(choice) <= len(u['options']):
                answers[u['id']] = u['options'][int(choice) - 1]
            else:
                answers[u['id']] = choice
        else:
            answers[u['id']] = input('   Answer: ').strip() or u.get('default', '')
    return answers

import anthropic, json

client = anthropic.AsyncAnthropic()

async def run_with_human_as_tool(
    task:          str,
    domain_tools:  list[dict],
    action_id:     str,
) -> str:
    tools = [CLARIFY_TOOL] + domain_tools
    messages = [{'role': 'user', 'content': task}]

    while True:
        response = await client.messages.create(
            model="claude-opus-4-8",
            max_tokens=2048,
            tools=tools,
            messages=messages,
        )
        messages.append({'role': 'assistant', 'content': response.content})

        if response.stop_reason == 'end_turn':
            return next(b.text for b in response.content if b.type == 'text')

        tool_results = []
        for block in response.content:
            if block.type != 'tool_use':
                continue

            if block.name == 'ask_human':
                # Route to human via async queue; agent blocks here
                answer = await ask_human_async(
                    action_id=action_id,
                    context=block.input.get('context', ''),
                    question=block.input['question'],
                    options=block.input.get('options'),
                    default=block.input.get('default'),
                )
                tool_results.append({
                    'type': 'tool_result',
                    'tool_use_id': block.id,
                    'content': answer,
                })
            else:
                result = await dispatch_tool(block.name, block.input)
                tool_results.append({
                    'type': 'tool_result',
                    'tool_use_id': block.id,
                    'content': json.dumps(result),
                })

        messages.append({'role': 'user', 'content': tool_results})

async def dispatch_tool(name: str, args: dict) -> dict:
    return {'status': 'ok', 'tool': name}
